const text = $input.first().json.message.text;

// Парсим поля из текста
const asset = {
  name: '',
  type: '',
  shortDescription: '',
  role: '',
  formAndComposition: '',
  colorAndMaterials: '',
  architecturalDetails: '',
  functionalElements: '',
  styleElements: '',
  generalStyle: '',
  colorPalette: []
};

let currentSection = '';

const lines = text.split('\n');

for (const line of lines) {
  const trimmed = line.trim();
  if (!trimmed) continue;

  if (trimmed.startsWith('Название:')) {
    asset.name = trimmed.replace('Название:', '').trim();
  } else if (trimmed.startsWith('Тип объекта:')) {
    asset.type = trimmed.replace('Тип объекта:', '').trim();
  } else if (trimmed.startsWith('Краткое описание:')) {
    currentSection = 'shortDescription';
  } else if (trimmed.startsWith('Роль/назначение:')) {
    currentSection = 'role';
  } else if (trimmed.startsWith('Форма и композиция:')) {
    currentSection = 'formAndComposition';
  } else if (trimmed.startsWith('Цвет и материалы:')) {
    currentSection = 'colorAndMaterials';
  } else if (trimmed.startsWith('Архитектурные детали:')) {
    currentSection = 'architecturalDetails';
  } else if (trimmed.startsWith('Функциональные элементы:')) {
    currentSection = 'functionalElements';
  } else if (trimmed.startsWith('Ключевые элементы стиля:')) {
    currentSection = 'styleElements';
  } else if (trimmed.startsWith('Общая стилистика проекта:')) {
    currentSection = 'generalStyle';
  } else if (trimmed.startsWith('Цветовая палитра:')) {
    currentSection = 'colorPalette';
  } else if (trimmed.startsWith('Описание и адаптация:')) {
    currentSection = '';
  } else if (currentSection) {
    if (currentSection === 'colorPalette') {
      const match = trimmed.match(/(.+?)\s*\((#[A-Fa-f0-9]{6})\)\s*используется для\s*(.+)/);
      if (match) {
        asset.colorPalette.push({
          name: match[1].trim(),
          hex: match[2],
          usage: match[3].replace(/\.$/, '').trim()
        });
      }
    } else {
      asset[currentSection] += (asset[currentSection] ? ' ' : '') + trimmed;
    }
  }
}

return [{ json: asset }];

