const data = $input.first().json;
const maxLength = 4000; // Лимит Telegram 4096, берём с запасом

const summary = data.summary;
const description = data.description;
const fullText = 'Задача: ' + summary + '\n\n' + description;

// Разбиваем текст на части
const parts = [];
let currentPart = '';
const lines = fullText.split('\n');

for (let i = 0; i < lines.length; i++) {
  const line = lines[i];

  if ((currentPart + '\n' + line).length > maxLength) {
    // Сохраняем текущую часть
    if (currentPart.length > 0) {
      parts.push(currentPart.trim());
    }
    currentPart = line;
  } else {
    currentPart = currentPart + (currentPart ? '\n' : '') + line;
  }
}

// Добавляем последнюю часть
if (currentPart.length > 0) {
  parts.push(currentPart.trim());
}

// Возвращаем массив сообщений
const messages = parts.map(function(part, index) {
  return {
    json: {
      text: parts.length > 1 ? '(' + (index + 1) + '/' + parts.length + ')\n\n' + part : part,
      partNumber: index + 1,
      totalParts: parts.length,
      summary: summary,
      qnapPath: data.qnapPath,
      assetType: data.assetType
    }
  };
});

return messages;
